SELECT SUM(absolute_dose_gy) AS TotalDose
FROM dose_distribution
WHERE patient_id = '<Specific Patient>';

SELECT *
FROM treatment_outcomes
WHERE session_id IN (
    SELECT session_id
    FROM treatment_sessions
    WHERE treatment_plan_id IN (
        SELECT treatment_plan_id
        FROM treatment_plans
        WHERE patient_id IN (
            SELECT patient_id FROM patients
        )
    )
);

SELECT COUNT(DISTINCT patient_id) AS total_patients
FROM dose_distribution
WHERE absolute_dose_gy > 5;

SELECT COUNT(*) AS scheduled_sessions
FROM treatment_sessions
WHERE status = 'scheduled';

SELECT machine_id, machine_name, created_at 
FROM radiation_machines 
WHERE created_at > '2022-01-01';
